const inputStyle = { width: "100%", boxSizing: "border-box", padding: "9px 11px", borderRadius: "9px", border: `1.5px solid ${COLORS.line}`, background: COLORS.paper, fontSize: "13px", color: COLORS.inkOnCream, fontFamily: "'Inter', sans-serif" };

function FieldLabel({ children }) {
  return <span style={{ display: "block", fontSize: "11.5px", fontWeight: 600, color: COLORS.muted, marginBottom: "5px" }}>{children}</span>;
}

function ProductThumb({ product, size }) {
  const s = size || 34;
  if (product.photo) {
    return <img src={product.photo} alt="" style={{ width: s, height: s, borderRadius: "9px", objectFit: "cover", flexShrink: 0 }} />;
  }
  return (
    <div style={{ width: s, height: s, borderRadius: "9px", background: COLORS.cream, border: `1px solid ${COLORS.line}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: s * 0.55 + "px", flexShrink: 0 }}>
      {product.emoji}
    </div>
  );
}

function Pill({ children, tone }) {
  const tones = {
    ok: { bg: "rgba(63,122,82,0.14)", fg: COLORS.green },
    warn: { bg: "rgba(217,142,43,0.16)", fg: COLORS.amberDark },
    info: { bg: "rgba(59,91,140,0.14)", fg: COLORS.blue },
    danger: { bg: "rgba(181,70,47,0.12)", fg: COLORS.red },
    muted: { bg: COLORS.line, fg: COLORS.muted },
  };
  const t = tones[tone] || tones.muted;
  return <span style={{ background: t.bg, color: t.fg, fontSize: "10px", fontWeight: 700, padding: "3px 9px", borderRadius: "999px" }}>{children}</span>;
}

const stepBtnStyle = { width: "26px", height: "26px", border: "none", background: COLORS.paper, color: COLORS.navy, fontSize: "15px", fontWeight: 600, cursor: "pointer", lineHeight: 1 };

function Stepper({ value, onChange, compact }) {
  return (
    <div style={{ display: "flex", alignItems: "center", border: `1.5px solid ${COLORS.line}`, borderRadius: "8px", overflow: "hidden", flexShrink: 0 }}>
      <button onClick={() => onChange(Math.max(0, value - 1))} style={stepBtnStyle} aria-label="Azalt">−</button>
      <span style={{ minWidth: compact ? "26px" : "32px", textAlign: "center", fontFamily: "'JetBrains Mono', monospace", fontWeight: 600, fontSize: "13px", color: COLORS.inkOnCream }}>{value}</span>
      <button onClick={() => onChange(value + 1)} style={stepBtnStyle} aria-label="Artır">+</button>
    </div>
  );
}

function currentBalance(cari) {
  if (cari.transactions.length === 0) return 0;
  return cari.transactions[cari.transactions.length - 1].balanceAfter;
}

// ---------- Sidebar ----------
function Sidebar({ view, setView, lowStockCount, activeOrderCount, businessInfo, onOpenBusiness }) {
  const NAV = [
    { key: "urunler", label: "Ürünler", icon: "📦", badge: lowStockCount > 0 ? lowStockCount : null, badgeTone: "danger" },
    { key: "malgirisi", label: "Mal Girişi", icon: "🚚" },
    { key: "satis", label: "Satış", icon: "🧾" },
    { key: "cari", label: "Cari / Veresiye", icon: "📒" },
    { key: "siparisler", label: "Siparişler", icon: "🛵", badge: activeOrderCount > 0 ? activeOrderCount : null, badgeTone: "amber" },
    { key: "vitrin", label: "Vitrin", icon: "🛍️" },
  ];
  return (
    <div style={{ width: "220px", flexShrink: 0, background: `linear-gradient(180deg, ${COLORS.navy}, ${COLORS.navySoft})`, color: COLORS.paper, display: "flex", flexDirection: "column", padding: "22px 14px" }}>
      <div style={{ padding: "0 8px", marginBottom: "26px" }}>
        <div style={{ display: "inline-block", background: COLORS.cream, borderRadius: "12px", padding: "8px 10px" }}>
          <img src={LOGO_SRC} alt="Depapp" style={{ height: "30px", width: "auto", display: "block" }} />
        </div>
      </div>
      <div style={{ padding: "0 8px", marginBottom: "22px" }}>
        <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "14.5px" }}>{businessInfo.name}</div>
        <div style={{ display: "flex", alignItems: "center", gap: "6px", marginTop: "4px" }}>
          <span style={{ width: "6px", height: "6px", borderRadius: "50%", background: COLORS.green }} />
          <span style={{ fontSize: "11px", color: "#A9B0C9" }}>Yayında</span>
        </div>
      </div>
      <nav style={{ display: "flex", flexDirection: "column", gap: "3px" }}>
        {NAV.map((n) => {
          const active = view === n.key;
          return (
            <button key={n.key} className="nav-row" onClick={() => setView(n.key)} style={{ display: "flex", alignItems: "center", gap: "10px", padding: "10px 10px", border: "none", borderRadius: "9px", cursor: "pointer", background: active ? "rgba(217,142,43,0.18)" : "transparent", color: active ? COLORS.amber : "#C7CCE0", fontWeight: 600, fontSize: "13.5px", textAlign: "left" }}>
              <span style={{ fontSize: "15px" }}>{n.icon}</span>
              {n.label}
              {n.badge && (
                <span style={{ marginLeft: "auto", background: n.badgeTone === "danger" ? COLORS.red : COLORS.amber, color: n.badgeTone === "danger" ? COLORS.paper : COLORS.navy, borderRadius: "999px", fontSize: "10px", fontWeight: 700, padding: "1px 7px" }}>
                  {n.badge}
                </span>
              )}
            </button>
          );
        })}
      </nav>
      <div style={{ marginTop: "auto" }}>
        <button className="nav-row" onClick={onOpenBusiness} style={{ display: "flex", alignItems: "center", gap: "10px", padding: "10px 10px", border: "none", borderRadius: "9px", cursor: "pointer", background: "transparent", color: "#C7CCE0", fontWeight: 600, fontSize: "13px", textAlign: "left", width: "100%" }}>
          <span style={{ fontSize: "14px" }}>⚙️</span> İşletme Bilgileri
        </button>
        <div style={{ padding: "12px 10px", borderTop: `1px solid ${COLORS.navyLine}` }}>
          <div style={{ fontSize: "11px", color: "#8891B5", lineHeight: 1.5 }}>Aylık plan: 149 ₺<br />Komisyon yok</div>
        </div>
      </div>
    </div>
  );
}

// ---------- App ----------
export default function DepappApp() {
  const [view, setView] = useState("satis");
  const [products, setProducts] = useState(INITIAL_PRODUCTS);
  const [cariList, setCariList] = useState(INITIAL_CARI);
  const [orders, setOrders] = useState(INITIAL_ORDERS);
  const [movementLog, setMovementLog] = useState([]);
  const [expenses, setExpenses] = useState([]);
  const [businessInfo, setBusinessInfo] = useState({
    name: "Yeşilova Manav", type: "Manav", phone: "0532 123 45 67",
    address: "Yeşilova Mah. Pazar Sk. No:12", workingHours: "08:00 – 21:00",
    serviceModel: { gelAl: true, kapiTeslimi: true, sepetHazirlama: false },
  });
  const [businessModalOpen, setBusinessModalOpen] = useState(false);

  const lowStockCount = products.filter((p) => p.stock <= p.minStockAlert).length;
  const activeOrderCount = orders.filter((o) => o.status !== "tamamlandi").length;

  const adjustStock = (productId, delta) => {
    setProducts((prev) => prev.map((p) => (p.id === productId ? { ...p, stock: Math.max(0, p.stock + delta) } : p)));
  };

  const logMovement = (entry) => {
    setMovementLog((prev) => [{ id: "m" + Date.now() + Math.random(), timestamp: new Date().toLocaleString("tr-TR", { day: "2-digit", month: "2-digit", hour: "2-digit", minute: "2-digit" }), ...entry }, ...prev]);
  };

  const addCariTransaction = (cariId, type, amount, note) => {
    setCariList((prev) =>
      prev.map((c) => {
        if (c.id !== cariId) return c;
        const before = currentBalance(c);
        const delta = type === "veresiyeSatis" ? amount : type === "tahsilat" ? -amount : type === "malAlimiVeresiye" ? -amount : amount;
        const newTx = { id: "t" + Date.now() + Math.random(), type, amount, note, timestamp: new Date().toLocaleString("tr-TR", { day: "2-digit", month: "2-digit", hour: "2-digit", minute: "2-digit" }), balanceAfter: before + delta };
        return { ...c, transactions: [...c.transactions, newTx] };
      })
    );
  };

  return (
    <div style={{ minHeight: "100vh", background: "#E9E2D2", display: "flex", alignItems: "flex-start", justifyContent: "center", padding: "26px 18px", fontFamily: "'Inter', sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,600;9..144,700&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@500;600&display=swap');
        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 6px; height: 6px; }
        ::-webkit-scrollbar-thumb { background: ${COLORS.line}; border-radius: 4px; }
        .nav-row { transition: background 120ms ease, color 120ms ease; }
        .row-hover:hover { border-color: ${COLORS.amber} !important; }
        .primary-btn { transition: background 150ms ease, transform 100ms ease; cursor: pointer; }
        .primary-btn:not(:disabled):hover { background: ${COLORS.amberDark}; transform: translateY(-1px); }
        .ghost-btn { cursor: pointer; transition: background 120ms ease; }
        .ghost-btn:hover { background: ${COLORS.line}; }
        .cat-chip { transition: background 120ms ease, color 120ms ease, border-color 120ms ease; cursor: pointer; }
        .prod-card { transition: transform 100ms ease, border-color 100ms ease; cursor: pointer; }
        .prod-card:hover { transform: translateY(-2px); border-color: ${COLORS.amber}; }
        .cari-row { cursor: pointer; transition: background 120ms ease, border-color 120ms ease; }
        .cari-row:hover { border-color: ${COLORS.amber}; }
        .advance-btn { transition: background 150ms ease, transform 100ms ease; cursor: pointer; }
        .advance-btn:hover { background: ${COLORS.amberDark}; transform: translateY(-1px); }
        .toggle { cursor: pointer; }
        .flash { animation: flash-pop 900ms ease; }
        @keyframes flash-pop { 0% { box-shadow: 0 0 0 0 rgba(217,142,43,0.5);} 60% { box-shadow: 0 0 0 8px rgba(217,142,43,0);} 100% { box-shadow: 0 0 0 0 rgba(217,142,43,0);} }
        .scan-pulse { animation: pulse-ring 400ms ease-out; }
        @keyframes pulse-ring { 0% { box-shadow: 0 0 0 0 rgba(217,142,43,0.55);} 100% { box-shadow: 0 0 0 16px rgba(217,142,43,0);} }
        input:focus, select:focus { outline: none; border-color: ${COLORS.amber} !important; }
      `}</style>

      <div style={{ width: "100%", maxWidth: "1180px", height: "760px", background: COLORS.cream, borderRadius: "20px", overflow: "hidden", display: "flex", boxShadow: "0 24px 60px rgba(16,27,61,0.28)" }}>
        <Sidebar view={view} setView={setView} lowStockCount={lowStockCount} activeOrderCount={activeOrderCount} businessInfo={businessInfo} onOpenBusiness={() => setBusinessModalOpen(true)} />
        <div style={{ flex: 1, display: "flex", flexDirection: "column", minWidth: 0, position: "relative" }}>
          {view === "urunler" && <UrunlerView products={products} setProducts={setProducts} />}
          {view === "malgirisi" && <MalGirisiView products={products} adjustStock={adjustStock} logMovement={logMovement} cariList={cariList} setCariList={setCariList} addCariTransaction={addCariTransaction} movementLog={movementLog} setProducts={setProducts} expenses={expenses} setExpenses={setExpenses} />}
          {view === "satis" && <SatisView products={products} setProducts={setProducts} adjustStock={adjustStock} logMovement={logMovement} cariList={cariList} addCariTransaction={addCariTransaction} currentBalance={currentBalance} />}
          {view === "cari" && <CariView cariList={cariList} setCariList={setCariList} addCariTransaction={addCariTransaction} currentBalance={currentBalance} />}
          {view === "siparisler" && <SiparislerView orders={orders} setOrders={setOrders} adjustStock={adjustStock} logMovement={logMovement} />}
          {view === "vitrin" && <VitrinView products={products} businessInfo={businessInfo} />}
        </div>
      </div>
      {businessModalOpen && <BusinessInfoModal businessInfo={businessInfo} setBusinessInfo={setBusinessInfo} onClose={() => setBusinessModalOpen(false)} />}
    </div>
  );
}

function BusinessInfoModal({ businessInfo, setBusinessInfo, onClose }) {
  const [form, setForm] = useState(businessInfo);
  const set = (field) => (e) => setForm((prev) => ({ ...prev, [field]: e.target.value }));
  const toggleService = (key) => setForm((prev) => ({ ...prev, serviceModel: { ...prev.serviceModel, [key]: !prev.serviceModel[key] } }));
  const save = () => { setBusinessInfo(form); onClose(); };

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(16,27,61,0.45)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 60 }}>
      <div style={{ width: "440px", maxWidth: "92vw", background: COLORS.cream, borderRadius: "16px", padding: "22px", boxShadow: "0 20px 50px rgba(0,0,0,0.3)" }}>
        <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "17px", color: COLORS.inkOnCream, marginBottom: "16px" }}>İşletme Bilgileri</div>
        <div style={{ marginBottom: "12px" }}><FieldLabel>İşletme adı</FieldLabel><input value={form.name} onChange={set("name")} style={inputStyle} /></div>
        <div style={{ display: "flex", gap: "10px", marginBottom: "12px" }}>
          <div style={{ flex: 1 }}><FieldLabel>Tür</FieldLabel>
            <select value={form.type} onChange={set("type")} style={inputStyle}>
              {["Market", "Bakkal", "Manav", "Kasap", "Butik"].map((t) => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>
          <div style={{ flex: 1 }}><FieldLabel>Telefon</FieldLabel><input value={form.phone} onChange={set("phone")} style={inputStyle} /></div>
        </div>
        <div style={{ marginBottom: "12px" }}><FieldLabel>Adres</FieldLabel><input value={form.address} onChange={set("address")} style={inputStyle} /></div>
        <div style={{ marginBottom: "14px" }}><FieldLabel>Çalışma saatleri</FieldLabel><input value={form.workingHours} onChange={set("workingHours")} style={inputStyle} /></div>
        <div style={{ marginBottom: "18px" }}>
          <FieldLabel>Hizmet modeli (Depup'ta gösterilir)</FieldLabel>
          <div style={{ display: "flex", gap: "6px", flexWrap: "wrap" }}>
            {[{ key: "gelAl", label: "Gel-al" }, { key: "kapiTeslimi", label: "Kapıda teslim" }, { key: "sepetHazirlama", label: "Sepet hazırla" }].map((s) => (
              <span key={s.key} onClick={() => toggleService(s.key)} style={{ padding: "7px 12px", borderRadius: "999px", fontSize: "12px", fontWeight: 600, cursor: "pointer", border: `1.5px solid ${form.serviceModel[s.key] ? COLORS.amber : COLORS.line}`, background: form.serviceModel[s.key] ? "rgba(217,142,43,0.16)" : COLORS.paper, color: form.serviceModel[s.key] ? COLORS.amberDark : COLORS.muted }}>
                {form.serviceModel[s.key] ? "✓ " : ""}{s.label}
              </span>
            ))}
          </div>
        </div>
        <div style={{ display: "flex", gap: "10px" }}>
          <button className="ghost-btn" onClick={onClose} style={{ flex: 1, border: `1.5px solid ${COLORS.line}`, background: "transparent", borderRadius: "10px", padding: "11px 0", fontWeight: 600, fontSize: "13.5px", color: COLORS.muted }}>Vazgeç</button>
          <button className="primary-btn" onClick={save} style={{ flex: 1, border: "none", borderRadius: "10px", padding: "11px 0", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13.5px" }}>Kaydet</button>
        </div>
      </div>
    </div>
  );
}

// ---------- Vitrin (Depup önizleme) ----------
function VitrinView({ products, businessInfo }) {
  const listed = products.filter((p) => p.isOnVitrin && p.stock > 0);
  const withoutPhoto = listed.filter((p) => !p.photo).length;
  const activeServices = Object.entries(businessInfo.serviceModel).filter(([, v]) => v).map(([k]) => SERVICE_LABEL[k] || k);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
      <div style={{ padding: "18px 24px", borderBottom: `1px solid ${COLORS.line}`, flexShrink: 0, display: "flex", alignItems: "flex-start", gap: "16px" }}>
        <div style={{ marginRight: "auto" }}>
          <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "19px", color: COLORS.inkOnCream, marginBottom: "4px" }}>Vitrin — Depup'ta böyle görünüyor</div>
          <div style={{ fontSize: "12px", color: COLORS.muted }}>Yalnızca "Vitrinde" işaretli ve stoğu olan ürünler burada listelenir. Stok biterse otomatik kalkar.</div>
        </div>
        {withoutPhoto > 0 && (
          <div style={{ display: "flex", alignItems: "center", gap: "6px", background: "rgba(217,142,43,0.14)", border: `1px solid ${COLORS.amber}`, borderRadius: "10px", padding: "8px 12px", flexShrink: 0 }}>
            <span style={{ fontSize: "14px" }}>📷</span>
            <span style={{ fontSize: "11.5px", fontWeight: 600, color: COLORS.amberDark }}>{withoutPhoto} üründe fotoğraf yok — Ürünler'den ekleyebilirsin</span>
          </div>
        )}
      </div>
      <div style={{ flex: 1, overflowY: "auto", padding: "20px 24px", background: "#EFE9DA" }}>
        <div style={{ maxWidth: "440px", margin: "0 auto", background: COLORS.paper, borderRadius: "22px", overflow: "hidden", boxShadow: "0 10px 30px rgba(16,27,61,0.14)" }}>
          <div style={{ background: `linear-gradient(135deg, ${COLORS.navy}, ${COLORS.navySoft})`, color: COLORS.paper, padding: "18px 20px" }}>
            <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 700, fontSize: "17px" }}>{businessInfo.name}</div>
            <div style={{ fontSize: "11px", color: "#A9B0C9", marginTop: "3px" }}>{businessInfo.type} · 120 m uzakta · {businessInfo.workingHours}</div>
            <div style={{ display: "flex", gap: "6px", marginTop: "10px", flexWrap: "wrap" }}>
              {activeServices.map((s) => <Pill key={s} tone="amber">{s}</Pill>)}
              {activeServices.length === 0 && <span style={{ fontSize: "11px", color: "#A9B0C9" }}>Hizmet modeli seçilmedi — İşletme Bilgileri'nden ekle</span>}
            </div>
          </div>

          {listed.length === 0 ? (
            <div style={{ textAlign: "center", padding: "40px 16px", color: COLORS.muted, fontSize: "12.5px" }}>
              Şu an vitrinde ürün yok. Ürünler sekmesinden "Vitrinde" işaretle.
            </div>
          ) : (
            <div style={{ padding: "16px", display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px" }}>
              {listed.map((p) => (
                <div key={p.id} style={{ background: COLORS.cream, borderRadius: "14px", overflow: "hidden", border: `1px solid ${COLORS.line}` }}>
                  <div style={{ width: "100%", aspectRatio: "1 / 1", position: "relative", background: p.photo ? "transparent" : `linear-gradient(135deg, ${COLORS.navySoft}, ${COLORS.navy})` }}>
                    {p.photo ? (
                      <img src={p.photo} alt={p.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                    ) : (
                      <div style={{ width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "34px" }}>{p.emoji}</div>
                    )}
                    <span style={{ position: "absolute", top: "8px", right: "8px", background: "rgba(16,27,61,0.85)", color: COLORS.paper, fontFamily: "'JetBrains Mono', monospace", fontSize: "11px", fontWeight: 700, padding: "3px 8px", borderRadius: "999px" }}>
                      {p.salePrice} ₺
                    </span>
                  </div>
                  <div style={{ padding: "9px 10px 11px" }}>
                    <div style={{ fontSize: "12.5px", fontWeight: 600, color: COLORS.inkOnCream, lineHeight: 1.25 }}>{p.name}</div>
                    <div style={{ fontSize: "10.5px", color: COLORS.muted, marginTop: "3px" }}>{p.stock} {p.unit} mevcut</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
        <div style={{ textAlign: "center", marginTop: "14px", fontSize: "11.5px", color: COLORS.muted }}>
          {listed.length} ürün · Depup müşterileri seni bu şekilde görecek
        </div>
      </div>
    </div>
  );
}

// ---------- Ürünler ----------
const emptyProductForm = { name: "", cat: "Sebze", unit: "kg", barcode: "", costPrice: "", salePrice: "", minStockAlert: "", isOnVitrin: true, photo: null };

function UrunlerView({ products, setProducts }) {
  const [query, setQuery] = useState("");
  const [formOpen, setFormOpen] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [form, setForm] = useState(emptyProductForm);
  const [importOpen, setImportOpen] = useState(false);
  const [importText, setImportText] = useState("");
  const [importResult, setImportResult] = useState(null);

  const filtered = products.filter((p) => p.name.toLocaleLowerCase("tr").includes(query.toLocaleLowerCase("tr")));
  const vitrinCount = products.filter((p) => p.isOnVitrin && p.stock > 0).length;

  const openNew = () => { setForm(emptyProductForm); setEditingId(null); setFormOpen(true); };
  const openEdit = (p) => { setForm({ name: p.name, cat: p.cat, unit: p.unit, barcode: p.barcode, costPrice: p.costPrice, salePrice: p.salePrice, minStockAlert: p.minStockAlert, isOnVitrin: p.isOnVitrin, photo: p.photo || null }); setEditingId(p.id); setFormOpen(true); };

  const runImport = () => {
    const lines = importText.split("\n").map((l) => l.trim()).filter(Boolean);
    const newProducts = [];
    lines.forEach((line) => {
      const parts = line.split(/[,;\t]/).map((s) => s.trim());
      if (!parts[0]) return;
      const [name, unit, costPrice, salePrice, stock, cat] = parts;
      newProducts.push({
        id: Date.now() + Math.random(),
        emoji: EMOJI_BY_CAT[cat] || "📦",
        name,
        cat: CATEGORIES.includes(cat) ? cat : "Diğer",
        unit: UNITS.includes(unit) ? unit : "adet",
        barcode: "",
        costPrice: Number(costPrice) || 0,
        salePrice: Number(salePrice) || 0,
        stock: Number(stock) || 0,
        minStockAlert: 5,
        isOnVitrin: false,
      });
    });
    if (newProducts.length > 0) {
      setProducts((prev) => [...newProducts, ...prev]);
      setImportResult({ count: newProducts.length });
      setImportText("");
      setTimeout(() => { setImportResult(null); setImportOpen(false); }, 1600);
    }
  };

  const save = () => {
    if (!form.name.trim()) return;
    if (editingId) {
      setProducts((prev) => prev.map((p) => (p.id === editingId ? { ...p, ...form, costPrice: Number(form.costPrice) || 0, salePrice: Number(form.salePrice) || 0, minStockAlert: Number(form.minStockAlert) || 0 } : p)));
    } else {
      setProducts((prev) => [{ id: Date.now(), emoji: EMOJI_BY_CAT[form.cat] || "📦", ...form, costPrice: Number(form.costPrice) || 0, salePrice: Number(form.salePrice) || 0, minStockAlert: Number(form.minStockAlert) || 0, stock: 0 }, ...prev]);
    }
    setFormOpen(false);
  };

  const toggleVitrin = (id) => setProducts((prev) => prev.map((p) => (p.id === id ? { ...p, isOnVitrin: !p.isOnVitrin } : p)));

  return (
    <>
      <div style={{ display: "flex", alignItems: "center", gap: "12px", padding: "18px 24px", borderBottom: `1px solid ${COLORS.line}`, flexShrink: 0 }}>
        <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "19px", color: COLORS.inkOnCream }}>Ürün Tanımlama</div>
        <Pill tone="ok">{vitrinCount} ürün Depup vitrininde</Pill>
        <button className="ghost-btn" onClick={() => setImportOpen(true)} style={{ marginLeft: "auto", border: `1.5px solid ${COLORS.line}`, background: COLORS.paper, borderRadius: "10px", padding: "9px 16px", color: COLORS.muted, fontWeight: 600, fontSize: "13px" }}>⇪ Toplu içe aktar</button>
        <button className="primary-btn" onClick={openNew} style={{ border: "none", borderRadius: "10px", padding: "9px 16px", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13px" }}>+ Yeni ürün</button>
      </div>
      <div style={{ padding: "14px 24px 0", flexShrink: 0 }}>
        <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Ürün ara..." style={{ ...inputStyle, maxWidth: "280px" }} />
      </div>
      <div style={{ flex: 1, overflowY: "auto", padding: "14px 24px 24px" }}>
        <div style={{ display: "grid", gridTemplateColumns: "1.6fr 80px 80px 80px 80px 130px 90px", padding: "0 14px 8px", fontSize: "10.5px", fontWeight: 700, letterSpacing: "0.04em", color: COLORS.muted, textTransform: "uppercase" }}>
          <span>Ürün</span><span>Birim</span><span>Alış</span><span>Satış</span><span>Stok</span><span>Vitrin</span><span></span>
        </div>
        {filtered.map((p) => {
          const low = p.stock <= p.minStockAlert;
          const outOfStockButListed = p.isOnVitrin && p.stock === 0;
          return (
            <div key={p.id} className="row-hover" style={{ display: "grid", gridTemplateColumns: "1.6fr 80px 80px 80px 80px 130px 90px", alignItems: "center", background: COLORS.paper, border: `1px solid ${low ? "rgba(181,70,47,0.35)" : COLORS.line}`, borderRadius: "12px", padding: "10px 14px", marginBottom: "8px" }}>
              <div style={{ display: "flex", alignItems: "center", gap: "10px", minWidth: 0 }}>
                <ProductThumb product={p} size={34} />
                <div style={{ minWidth: 0 }}>
                  <div style={{ fontSize: "13px", fontWeight: 600, color: COLORS.inkOnCream }}>{p.name}</div>
                  <div style={{ fontSize: "10.5px", color: COLORS.muted }}>{p.cat} · {p.barcode}</div>
                </div>
              </div>
              <span style={{ fontSize: "12.5px", color: COLORS.muted }}>{p.unit}</span>
              <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "12px", color: COLORS.muted }}>{p.costPrice} ₺</span>
              <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "12.5px", color: COLORS.inkOnCream, fontWeight: 600 }}>{p.salePrice} ₺</span>
              <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "12.5px", color: low ? COLORS.red : COLORS.inkOnCream }}>{p.stock} {low && "⚠"}</span>
              <span className="toggle" onClick={() => toggleVitrin(p.id)}>
                <Pill tone={outOfStockButListed ? "danger" : p.isOnVitrin ? "ok" : "muted"}>
                  {outOfStockButListed ? "Stok yok — düştü" : p.isOnVitrin ? "Vitrinde" : "Vitrin dışı"}
                </Pill>
              </span>
              <button className="ghost-btn" onClick={() => openEdit(p)} style={{ border: `1.5px solid ${COLORS.line}`, background: "transparent", borderRadius: "8px", padding: "6px 10px", fontSize: "11.5px", fontWeight: 600, color: COLORS.muted }}>Düzenle</button>
            </div>
          );
        })}
      </div>
      {formOpen && <ProductFormModal form={form} setForm={setForm} onCancel={() => setFormOpen(false)} onSave={save} isEditing={!!editingId} />}
      {importOpen && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(16,27,61,0.45)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 50 }}>
          <div style={{ width: "520px", maxWidth: "92vw", background: COLORS.cream, borderRadius: "16px", padding: "22px", boxShadow: "0 20px 50px rgba(0,0,0,0.3)" }}>
            <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "17px", color: COLORS.inkOnCream, marginBottom: "8px" }}>Kendi stok listeni yapıştır</div>
            <div style={{ fontSize: "12px", color: COLORS.muted, marginBottom: "12px", lineHeight: 1.5 }}>
              Zaten bir Excel/stok listen varsa, her satıra bir ürün gelecek şekilde şu sırayla yapıştır (virgül veya sekmeyle ayır):<br />
              <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "11px" }}>Ürün adı, Birim, Alış fiyatı, Satış fiyatı, Stok, Kategori</span>
            </div>
            <textarea
              value={importText}
              onChange={(e) => setImportText(e.target.value)}
              placeholder={"Domates, kg, 24, 38, 24, Sebze\nAyran, adet, 8, 14, 30, Diğer"}
              rows={7}
              style={{ ...inputStyle, fontFamily: "'JetBrains Mono', monospace", fontSize: "12px", resize: "vertical", marginBottom: "14px" }}
            />
            <div style={{ display: "flex", gap: "10px" }}>
              <button className="ghost-btn" onClick={() => setImportOpen(false)} style={{ flex: 1, border: `1.5px solid ${COLORS.line}`, background: "transparent", borderRadius: "10px", padding: "11px 0", fontWeight: 600, fontSize: "13.5px", color: COLORS.muted }}>Vazgeç</button>
              <button className="primary-btn" onClick={runImport} style={{ flex: 1, border: "none", borderRadius: "10px", padding: "11px 0", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13.5px" }}>
                {importResult ? `✓ ${importResult.count} ürün eklendi` : "İçe aktar"}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

function ProductFormModal({ form, setForm, onCancel, onSave, isEditing }) {
  const set = (field) => (e) => setForm((prev) => ({ ...prev, [field]: e.target.value }));
  const handlePhoto = (e) => {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => setForm((prev) => ({ ...prev, photo: reader.result }));
    reader.readAsDataURL(file);
  };
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(16,27,61,0.45)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 50 }}>
      <div style={{ width: "420px", maxWidth: "92vw", maxHeight: "88vh", overflowY: "auto", background: COLORS.cream, borderRadius: "16px", padding: "22px", boxShadow: "0 20px 50px rgba(0,0,0,0.3)" }}>
        <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "17px", color: COLORS.inkOnCream, marginBottom: "16px" }}>{isEditing ? "Ürünü düzenle" : "Yeni ürün tanımla"}</div>
        <div style={{ marginBottom: "14px" }}>
          <FieldLabel>Ürün fotoğrafı</FieldLabel>
          <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
            <div style={{ width: "64px", height: "64px", borderRadius: "12px", overflow: "hidden", background: COLORS.paper, border: `1.5px solid ${COLORS.line}`, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
              {form.photo ? <img src={form.photo} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : <span style={{ fontSize: "24px", opacity: 0.3 }}>📷</span>}
            </div>
            <label style={{ border: `1.5px solid ${COLORS.line}`, background: COLORS.paper, borderRadius: "9px", padding: "9px 14px", fontSize: "12px", fontWeight: 600, color: COLORS.muted, cursor: "pointer" }}>
              {form.photo ? "Fotoğrafı değiştir" : "Fotoğraf yükle"}
              <input type="file" accept="image/*" onChange={handlePhoto} style={{ display: "none" }} />
            </label>
            {form.photo && <button type="button" onClick={() => setForm((prev) => ({ ...prev, photo: null }))} style={{ border: "none", background: "transparent", color: COLORS.red, fontSize: "12px", fontWeight: 600, cursor: "pointer" }}>Kaldır</button>}
          </div>
        </div>
        <div style={{ marginBottom: "12px" }}><FieldLabel>Ürün adı</FieldLabel><input value={form.name} onChange={set("name")} placeholder="ör. Domates" style={inputStyle} /></div>
        <div style={{ display: "flex", gap: "10px", marginBottom: "12px" }}>
          <div style={{ flex: 1 }}><FieldLabel>Kategori</FieldLabel><select value={form.cat} onChange={set("cat")} style={inputStyle}>{CATEGORIES.map((c) => <option key={c} value={c}>{c}</option>)}</select></div>
          <div style={{ flex: 1 }}><FieldLabel>Birim</FieldLabel><select value={form.unit} onChange={set("unit")} style={inputStyle}>{UNITS.map((u) => <option key={u} value={u}>{u}</option>)}</select></div>
        </div>
        <div style={{ marginBottom: "12px" }}><FieldLabel>Barkod</FieldLabel><input value={form.barcode} onChange={set("barcode")} placeholder="El terminaliyle okutulacak kod" style={inputStyle} /></div>
        <div style={{ display: "flex", gap: "10px", marginBottom: "12px" }}>
          <div style={{ flex: 1 }}><FieldLabel>Alış fiyatı</FieldLabel><input type="number" value={form.costPrice} onChange={set("costPrice")} style={inputStyle} /></div>
          <div style={{ flex: 1 }}><FieldLabel>Satış fiyatı</FieldLabel><input type="number" value={form.salePrice} onChange={set("salePrice")} style={inputStyle} /></div>
        </div>
        <div style={{ marginBottom: "16px" }}><FieldLabel>Azalan stok eşiği</FieldLabel><input type="number" value={form.minStockAlert} onChange={set("minStockAlert")} placeholder="ör. 5" style={inputStyle} /></div>
        <div className="toggle" onClick={() => setForm((prev) => ({ ...prev, isOnVitrin: !prev.isOnVitrin }))} style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "20px" }}>
          <div style={{ width: "38px", height: "22px", borderRadius: "999px", background: form.isOnVitrin ? COLORS.amber : COLORS.line, position: "relative", transition: "background 150ms ease" }}>
            <div style={{ width: "18px", height: "18px", borderRadius: "50%", background: COLORS.paper, position: "absolute", top: "2px", left: form.isOnVitrin ? "18px" : "2px", transition: "left 150ms ease" }} />
          </div>
          <span style={{ fontSize: "13px", fontWeight: 600, color: COLORS.inkOnCream }}>Vitrinde yayınla (Depup'ta görünsün)</span>
        </div>
        <div style={{ display: "flex", gap: "10px" }}>
          <button className="ghost-btn" onClick={onCancel} style={{ flex: 1, border: `1.5px solid ${COLORS.line}`, background: "transparent", borderRadius: "10px", padding: "11px 0", fontWeight: 600, fontSize: "13.5px", color: COLORS.muted }}>Vazgeç</button>
          <button className="primary-btn" onClick={onSave} style={{ flex: 1, border: "none", borderRadius: "10px", padding: "11px 0", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13.5px" }}>Kaydet</button>
        </div>
      </div>
    </div>
  );
}

// ---------- Mal Girişi ----------
function MalGirisiView({ products, adjustStock, logMovement, cariList, setCariList, addCariTransaction, movementLog, setProducts, expenses, setExpenses }) {
  const suppliers = cariList.filter((c) => c.type === "tedarikci");
  const [mode, setMode] = useState("mal"); // 'mal' | 'gider'
  const [supplierId, setSupplierId] = useState(suppliers[0]?.id || "");
  const [receivingLines, setReceivingLines] = useState([]);
  const [productPick, setProductPick] = useState("");
  const [isPaidNow, setIsPaidNow] = useState(true);
  const [receiptFlash, setReceiptFlash] = useState(false);
  const [newSupplierOpen, setNewSupplierOpen] = useState(false);
  const [newSupplierForm, setNewSupplierForm] = useState({ name: "", phone: "" });
  const [expenseForm, setExpenseForm] = useState({ category: "Kira", amount: "", note: "" });
  const [expenseFlash, setExpenseFlash] = useState(false);

  const saveNewSupplier = () => {
    if (!newSupplierForm.name.trim()) return;
    const newSupplier = { id: "c" + Date.now(), name: newSupplierForm.name, phone: newSupplierForm.phone, type: "tedarikci", creditLimit: 0, transactions: [] };
    setCariList((prev) => [newSupplier, ...prev]);
    setSupplierId(newSupplier.id);
    setNewSupplierOpen(false);
    setNewSupplierForm({ name: "", phone: "" });
  };

  const addExpense = () => {
    const amt = Number(expenseForm.amount);
    if (!amt || amt <= 0) return;
    setExpenses((prev) => [{ id: "e" + Date.now(), category: expenseForm.category, amount: amt, note: expenseForm.note, timestamp: new Date().toLocaleString("tr-TR", { day: "2-digit", month: "2-digit", hour: "2-digit", minute: "2-digit" }) }, ...prev]);
    setExpenseForm({ category: "Kira", amount: "", note: "" });
    setExpenseFlash(true);
    setTimeout(() => setExpenseFlash(false), 1500);
  };

  const addLine = () => {
    if (!productPick) return;
    const p = products.find((pp) => String(pp.id) === String(productPick));
    if (!p) return;
    setReceivingLines((prev) => {
      const existing = prev.find((l) => l.productId === p.id);
      if (existing) return prev.map((l) => (l.productId === p.id ? { ...l, qty: l.qty + 1 } : l));
      return [...prev, { productId: p.id, qty: 1, unitCost: p.costPrice }];
    });
    setProductPick("");
  };
  const updateLine = (productId, field, value) => setReceivingLines((prev) => prev.map((l) => (l.productId === productId ? { ...l, [field]: value } : l)));
  const removeLine = (productId) => setReceivingLines((prev) => prev.filter((l) => l.productId !== productId));

  const receivingTotal = receivingLines.reduce((sum, l) => { const p = products.find((pp) => pp.id === l.productId); return sum + (p ? Number(l.unitCost) * Number(l.qty) : 0); }, 0);

  const complete = () => {
    if (receivingLines.length === 0) return;
    const supplier = suppliers.find((s) => s.id === supplierId);
    receivingLines.forEach((l) => {
      adjustStock(l.productId, Number(l.qty));
      setProducts((prev) => prev.map((p) => (p.id === l.productId ? { ...p, costPrice: Number(l.unitCost) } : p)));
      const p = products.find((pp) => pp.id === l.productId);
      logMovement({ productName: p ? p.name : "?", emoji: p ? p.emoji : "📦", type: "malGirisi", quantity: l.qty, unit: p ? p.unit : "", source: "manuel", relatedCariId: supplierId, note: `${supplier ? supplier.name : "-"}'dan mal girişi` });
    });
    if (!isPaidNow && supplierId) addCariTransaction(supplierId, "malAlimiVeresiye", receivingTotal, "Mal girişi (veresiye)");
    setReceivingLines([]);
    setReceiptFlash(true);
    setTimeout(() => setReceiptFlash(false), 1800);
  };

  const recent = movementLog.filter((m) => m.type === "malGirisi").slice(0, 12);

  return (
    <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
      <div style={{ flex: 1.4, display: "flex", flexDirection: "column", minWidth: 0, borderRight: `1px solid ${COLORS.line}` }}>
        <div style={{ padding: "18px 24px 10px", borderBottom: `1px solid ${COLORS.line}`, flexShrink: 0 }}>
          <div style={{ display: "flex", alignItems: "center", gap: "12px", marginBottom: "12px" }}>
            <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "19px", color: COLORS.inkOnCream }}>
              {mode === "mal" ? "Mal Girişi" : "Genel Gider"}
            </div>
            <div style={{ display: "flex", gap: "6px", marginLeft: "auto" }}>
              {[{ key: "mal", label: "Mal Girişi" }, { key: "gider", label: "Genel Gider" }].map((m) => (
                <button key={m.key} onClick={() => setMode(m.key)} style={{ padding: "6px 12px", borderRadius: "999px", fontSize: "11.5px", fontWeight: 600, cursor: "pointer", border: `1.5px solid ${mode === m.key ? COLORS.amber : COLORS.line}`, background: mode === m.key ? "rgba(217,142,43,0.16)" : COLORS.paper, color: mode === m.key ? COLORS.amberDark : COLORS.muted }}>{m.label}</button>
              ))}
            </div>
          </div>

          {mode === "mal" ? (
            <div style={{ display: "flex", gap: "10px" }}>
              <div style={{ flex: 1 }}>
                <FieldLabel>Tedarikçi</FieldLabel>
                <div style={{ display: "flex", gap: "6px" }}>
                  <select value={supplierId} onChange={(e) => setSupplierId(e.target.value)} style={inputStyle}>
                    {suppliers.length === 0 && <option value="">Tedarikçi yok</option>}
                    {suppliers.map((s) => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                  <button className="ghost-btn" onClick={() => setNewSupplierOpen(true)} style={{ border: `1.5px solid ${COLORS.line}`, background: COLORS.paper, borderRadius: "9px", padding: "0 12px", fontSize: "12px", fontWeight: 700, color: COLORS.amberDark, flexShrink: 0 }}>+ Yeni</button>
                </div>
              </div>
              <div style={{ flex: 1.4 }}>
                <FieldLabel>Ürün ekle</FieldLabel>
                <div style={{ display: "flex", gap: "6px" }}>
                  <select value={productPick} onChange={(e) => setProductPick(e.target.value)} style={inputStyle}>
                    <option value="">Ürün seç...</option>
                    {products.map((p) => <option key={p.id} value={p.id}>{p.emoji} {p.name}</option>)}
                  </select>
                  <button className="primary-btn" onClick={addLine} style={{ border: "none", borderRadius: "9px", padding: "0 14px", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13px", flexShrink: 0 }}>Ekle</button>
                </div>
              </div>
            </div>
          ) : (
            <div style={{ fontSize: "12px", color: COLORS.muted }}>Kira, fatura, personel gibi stoğa girmeyen giderleri buradan kaydet.</div>
          )}
        </div>

        {mode === "mal" ? (
        <div style={{ flex: 1, overflowY: "auto", padding: "14px 24px" }}>
          {receivingLines.length === 0 && <div style={{ textAlign: "center", padding: "50px 10px", color: COLORS.muted, fontSize: "12.5px" }}>Yukarıdan ürün seçip "Ekle"ye bas, gelen mallar burada listelensin.</div>}
          {receivingLines.map((l) => {
            const p = products.find((pp) => pp.id === l.productId);
            if (!p) return null;
            return (
              <div key={l.productId} style={{ display: "flex", alignItems: "center", gap: "10px", background: COLORS.paper, border: `1px solid ${COLORS.line}`, borderRadius: "12px", padding: "10px 12px", marginBottom: "8px" }}>
                <span style={{ fontSize: "19px" }}>{p.emoji}</span>
                <div style={{ flex: 1, fontSize: "13px", fontWeight: 600, color: COLORS.inkOnCream }}>{p.name}</div>
                <div><FieldLabel>Miktar ({p.unit})</FieldLabel><input type="number" value={l.qty} onChange={(e) => updateLine(l.productId, "qty", Number(e.target.value))} style={{ ...inputStyle, width: "80px" }} /></div>
                <div><FieldLabel>Birim alış</FieldLabel><input type="number" value={l.unitCost} onChange={(e) => updateLine(l.productId, "unitCost", Number(e.target.value))} style={{ ...inputStyle, width: "90px" }} /></div>
                <button className="ghost-btn" onClick={() => removeLine(l.productId)} style={{ border: "none", background: "transparent", color: COLORS.red, fontSize: "13px", padding: "6px" }}>✕</button>
              </div>
            );
          })}
        </div>
        ) : (
        <div style={{ flex: 1, overflowY: "auto", padding: "18px 24px" }}>
          <div style={{ display: "flex", gap: "10px", marginBottom: "12px" }}>
            <div style={{ flex: 1 }}>
              <FieldLabel>Kategori</FieldLabel>
              <select value={expenseForm.category} onChange={(e) => setExpenseForm((p) => ({ ...p, category: e.target.value }))} style={inputStyle}>
                {["Kira", "Fatura", "Personel", "Nakliye", "Diğer"].map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div style={{ flex: 1 }}>
              <FieldLabel>Tutar</FieldLabel>
              <input type="number" value={expenseForm.amount} onChange={(e) => setExpenseForm((p) => ({ ...p, amount: e.target.value }))} placeholder="0" style={inputStyle} />
            </div>
          </div>
          <div style={{ marginBottom: "12px" }}>
            <FieldLabel>Not (opsiyonel)</FieldLabel>
            <input value={expenseForm.note} onChange={(e) => setExpenseForm((p) => ({ ...p, note: e.target.value }))} placeholder="ör. Temmuz ayı kira" style={inputStyle} />
          </div>
          <button className="primary-btn" onClick={addExpense} style={{ border: "none", borderRadius: "9px", padding: "10px 16px", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13px" }}>
            {expenseFlash ? "✓ Gider eklendi" : "Gideri kaydet"}
          </button>
        </div>
        )}
      </div>
      <div style={{ width: "320px", flexShrink: 0, display: "flex", flexDirection: "column", background: "#FBF9F3" }}>
        {mode === "mal" ? (
          <>
            <div style={{ padding: "16px 20px 10px", borderBottom: `1px solid ${COLORS.line}` }}>
              <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "15.5px", color: COLORS.inkOnCream }}>Fiş Özeti</div>
              <div style={{ fontSize: "11.5px", color: COLORS.muted, marginTop: "2px" }}>{receivingLines.length} kalem</div>
            </div>
            <div style={{ flex: 1, overflowY: "auto", padding: "10px 16px" }}>
              {recent.length === 0 ? <div style={{ fontSize: "12px", color: COLORS.muted, padding: "10px 4px" }}>Henüz kayıtlı giriş yok.</div> :
                recent.map((m) => (
                  <div key={m.id} style={{ padding: "8px 6px", borderBottom: `1px solid ${COLORS.line}` }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: "12.5px", fontWeight: 600, color: COLORS.inkOnCream }}>
                      <span>{m.emoji} {m.productName}</span>
                      <span style={{ fontFamily: "'JetBrains Mono', monospace" }}>+{m.quantity} {m.unit}</span>
                    </div>
                    <div style={{ fontSize: "10.5px", color: COLORS.muted, marginTop: "2px" }}>{m.note} · {m.timestamp}</div>
                  </div>
                ))}
            </div>
            <div style={{ padding: "14px 20px", borderTop: `1px solid ${COLORS.line}` }}>
              <div className="toggle" style={{ display: "flex", gap: "6px", marginBottom: "12px" }}>
                {["Peşin ödendi", "Veresiye (borç yaz)"].map((label, i) => {
                  const selected = (i === 0) === isPaidNow;
                  return <span key={label} onClick={() => setIsPaidNow(i === 0)} style={{ flex: 1, textAlign: "center", padding: "8px 4px", borderRadius: "9px", fontSize: "11px", fontWeight: 600, cursor: "pointer", border: `1.5px solid ${selected ? COLORS.amber : COLORS.line}`, background: selected ? "rgba(217,142,43,0.16)" : COLORS.paper, color: selected ? COLORS.amberDark : COLORS.muted }}>{label}</span>;
                })}
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: "12px" }}>
                <span style={{ fontSize: "13px", color: COLORS.muted, fontWeight: 600 }}>Toplam tutar</span>
                <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "20px", fontWeight: 700, color: COLORS.navy }}>{receivingTotal.toLocaleString("tr-TR")} ₺</span>
              </div>
              <button className="primary-btn" disabled={receivingLines.length === 0} onClick={complete} style={{ width: "100%", padding: "13px 0", border: "none", borderRadius: "10px", background: receivingLines.length === 0 ? COLORS.line : COLORS.amber, color: receivingLines.length === 0 ? COLORS.muted : COLORS.navy, fontWeight: 700, fontSize: "14px" }}>
                {receiptFlash ? "✓ Girişi kaydedildi" : "Girişi tamamla"}
              </button>
            </div>
          </>
        ) : (
          <>
            <div style={{ padding: "16px 20px 10px", borderBottom: `1px solid ${COLORS.line}` }}>
              <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "15.5px", color: COLORS.inkOnCream }}>Gider Geçmişi</div>
              <div style={{ fontSize: "11.5px", color: COLORS.muted, marginTop: "2px" }}>
                {expenses.reduce((s, e) => s + e.amount, 0).toLocaleString("tr-TR")} ₺ toplam
              </div>
            </div>
            <div style={{ flex: 1, overflowY: "auto", padding: "10px 16px" }}>
              {expenses.length === 0 ? <div style={{ fontSize: "12px", color: COLORS.muted, padding: "10px 4px" }}>Henüz gider kaydı yok.</div> :
                expenses.map((e) => (
                  <div key={e.id} style={{ padding: "8px 6px", borderBottom: `1px solid ${COLORS.line}` }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: "12.5px", fontWeight: 600, color: COLORS.inkOnCream }}>
                      <span><Pill tone="muted">{e.category}</Pill></span>
                      <span style={{ fontFamily: "'JetBrains Mono', monospace" }}>{e.amount} ₺</span>
                    </div>
                    <div style={{ fontSize: "10.5px", color: COLORS.muted, marginTop: "3px" }}>{e.note || "—"} · {e.timestamp}</div>
                  </div>
                ))}
            </div>
          </>
        )}
      </div>
      {newSupplierOpen && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(16,27,61,0.45)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 55 }}>
          <div style={{ width: "360px", maxWidth: "92vw", background: COLORS.cream, borderRadius: "16px", padding: "22px", boxShadow: "0 20px 50px rgba(0,0,0,0.3)" }}>
            <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "17px", color: COLORS.inkOnCream, marginBottom: "16px" }}>Yeni tedarikçi ekle</div>
            <div style={{ marginBottom: "12px" }}><FieldLabel>Ad</FieldLabel><input value={newSupplierForm.name} onChange={(e) => setNewSupplierForm((p) => ({ ...p, name: e.target.value }))} placeholder="ör. Toptancı Hasan" style={inputStyle} /></div>
            <div style={{ marginBottom: "18px" }}><FieldLabel>Telefon</FieldLabel><input value={newSupplierForm.phone} onChange={(e) => setNewSupplierForm((p) => ({ ...p, phone: e.target.value }))} placeholder="05xx xxx xx xx" style={inputStyle} /></div>
            <div style={{ display: "flex", gap: "10px" }}>
              <button className="ghost-btn" onClick={() => setNewSupplierOpen(false)} style={{ flex: 1, border: `1.5px solid ${COLORS.line}`, background: "transparent", borderRadius: "10px", padding: "11px 0", fontWeight: 600, fontSize: "13.5px", color: COLORS.muted }}>Vazgeç</button>
              <button className="primary-btn" onClick={saveNewSupplier} style={{ flex: 1, border: "none", borderRadius: "10px", padding: "11px 0", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13.5px" }}>Kaydet</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ---------- Satış ----------
function SatisView({ products, setProducts, adjustStock, logMovement, cariList, addCariTransaction, currentBalance }) {
  const [query, setQuery] = useState("");
  const [category, setCategory] = useState("Tümü");
  const [cart, setCart] = useState({});
  const [payment, setPayment] = useState("Nakit");
  const [selectedCariId, setSelectedCariId] = useState("");
  const [completedFlash, setCompletedFlash] = useState(false);
  const [scanBuffer, setScanBuffer] = useState("");
  const [lastScan, setLastScan] = useState(null);
  const scannerRef = React.useRef(null);
  const [quickAddOpen, setQuickAddOpen] = useState(false);
  const [quickAddForm, setQuickAddForm] = useState({ barcode: "", name: "", salePrice: "", costPrice: "", stock: "", unit: "adet", cat: "Diğer" });

  const customers = cariList.filter((c) => c.type === "musteri");
  const filtered = products.filter((p) => {
    const matchesCat = category === "Tümü" || p.cat === category;
    const matchesQuery = p.name.toLocaleLowerCase("tr").includes(query.toLocaleLowerCase("tr"));
    return matchesCat && matchesQuery;
  });

  const addToCart = (id) => setCart((prev) => {
    const product = products.find((p) => p.id === id);
    const current = prev[id] || 0;
    if (!product || current >= product.stock) return prev;
    return { ...prev, [id]: current + 1 };
  });
  const setCartQty = (id, qty) => setCart((prev) => {
    const product = products.find((p) => p.id === id);
    const capped = product ? Math.min(qty, product.stock) : qty;
    const next = { ...prev };
    if (capped <= 0) delete next[id];
    else next[id] = capped;
    return next;
  });

  const cartLines = Object.entries(cart).map(([id, qty]) => ({ product: products.find((p) => p.id === Number(id)), qty })).filter((l) => l.product);
  const total = cartLines.reduce((sum, l) => sum + l.product.salePrice * l.qty, 0);
  const itemCount = cartLines.reduce((sum, l) => sum + l.qty, 0);

  React.useEffect(() => { if (scannerRef.current) scannerRef.current.focus(); }, []);

  const handleTerminalScan = (code) => {
    const trimmed = code.trim();
    if (!trimmed) return;
    const product = products.find((p) => p.barcode === trimmed);
    if (product) {
      addToCart(product.id);
      setLastScan({ ok: true, label: `${product.emoji} ${product.name} sepete eklendi` });
      setScanBuffer("");
      setTimeout(() => setLastScan(null), 2200);
    } else {
      setQuickAddForm({ barcode: trimmed, name: "", salePrice: "", costPrice: "", stock: "1", unit: "adet", cat: "Diğer" });
      setQuickAddOpen(true);
      setScanBuffer("");
    }
  };

  const saveQuickAdd = () => {
    if (!quickAddForm.name.trim()) return;
    const newProduct = {
      id: Date.now(),
      emoji: EMOJI_BY_CAT[quickAddForm.cat] || "📦",
      name: quickAddForm.name,
      cat: quickAddForm.cat,
      unit: quickAddForm.unit,
      barcode: quickAddForm.barcode,
      costPrice: Number(quickAddForm.costPrice) || 0,
      salePrice: Number(quickAddForm.salePrice) || 0,
      stock: Number(quickAddForm.stock) || 0,
      minStockAlert: 5,
      isOnVitrin: false,
      photo: null,
    };
    setProducts((prev) => [newProduct, ...prev]);
    setQuickAddOpen(false);
    setTimeout(() => addToCart(newProduct.id), 0);
    setLastScan({ ok: true, label: `${newProduct.emoji} ${newProduct.name} kaydedildi ve sepete eklendi` });
    setTimeout(() => setLastScan(null), 2200);
  };

  const completeSale = () => {
    if (cartLines.length === 0) return;
    if (payment === "Veresiye" && !selectedCariId) return;
    cartLines.forEach((l) => {
      adjustStock(l.product.id, -l.qty);
      logMovement({ productName: l.product.name, emoji: l.product.emoji, type: "satis", quantity: -l.qty, unit: l.product.unit, source: "pos", note: `POS satışı (${payment})` });
    });
    if (payment === "Veresiye" && selectedCariId) addCariTransaction(selectedCariId, "veresiyeSatis", total, "POS veresiye satış");
    setCart({}); setSelectedCariId(""); setCompletedFlash(true);
    setTimeout(() => setCompletedFlash(false), 1800);
  };

  return (
    <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
      <div style={{ flex: 1.5, display: "flex", flexDirection: "column", minWidth: 0, borderRight: `1px solid ${COLORS.line}` }}>
        <div style={{ padding: "16px 24px 0", flexShrink: 0 }}>
          <div style={{ display: "flex", alignItems: "center", gap: "9px", background: COLORS.navy, borderRadius: "10px", padding: "8px 12px", marginBottom: "12px" }}>
            <span style={{ width: "7px", height: "7px", borderRadius: "50%", background: COLORS.green, flexShrink: 0, boxShadow: "0 0 0 3px rgba(63,122,82,0.3)" }} />
            <span style={{ fontSize: "11.5px", color: "#C7CCE0", fontWeight: 600, whiteSpace: "nowrap" }}>El terminali hazır</span>
            <input ref={scannerRef} value={scanBuffer} onChange={(e) => setScanBuffer(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") handleTerminalScan(scanBuffer); }} placeholder="Barkod bekleniyor" style={{ flex: 1, border: "none", background: "rgba(255,255,255,0.08)", borderRadius: "7px", padding: "6px 10px", fontFamily: "'JetBrains Mono', monospace", fontSize: "12px", color: COLORS.paper }} />
          </div>
          {lastScan && <div style={{ fontSize: "12px", fontWeight: 600, color: lastScan.ok ? COLORS.green : COLORS.red, marginBottom: "10px", marginTop: "-4px" }}>{lastScan.ok ? "✓" : "✕"} {lastScan.label}</div>}
        </div>
        <div style={{ padding: "0 24px 10px", flexShrink: 0 }}>
          <input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") {
                const trimmed = query.trim();
                const match = products.find((p) => p.barcode === trimmed);
                if (match) { addToCart(match.id); setQuery(""); }
                else if (/^\d{6,}$/.test(trimmed)) { handleTerminalScan(trimmed); setQuery(""); }
              }
            }}
            placeholder="Ürün ara veya barkodu elle yazıp Enter'a bas..."
            style={{ ...inputStyle, marginBottom: "10px" }}
          />
          <div style={{ display: "flex", gap: "7px", flexWrap: "wrap" }}>
            {["Tümü", ...CATEGORIES].map((c) => (
              <button key={c} className="cat-chip" onClick={() => setCategory(c)} style={{ padding: "6px 12px", borderRadius: "999px", fontSize: "12px", fontWeight: 600, border: `1.5px solid ${category === c ? COLORS.amber : COLORS.line}`, background: category === c ? "rgba(217,142,43,0.16)" : COLORS.paper, color: category === c ? COLORS.amberDark : COLORS.muted }}>{c}</button>
            ))}
          </div>
        </div>
        <div style={{ flex: 1, overflowY: "auto", padding: "6px 24px 24px", display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(128px, 1fr))", gap: "10px", alignContent: "start" }}>
          {filtered.map((p) => {
            const inCart = cart[p.id] || 0;
            const disabled = p.stock <= 0 || inCart >= p.stock;
            return (
              <div key={p.id} className="prod-card" onClick={() => !disabled && addToCart(p.id)} style={{ background: COLORS.paper, border: `1.5px solid ${COLORS.line}`, borderRadius: "12px", padding: "12px 10px", opacity: disabled ? 0.4 : 1, pointerEvents: disabled ? "none" : "auto" }}>
                <ProductThumb product={p} size={40} />
                <div style={{ fontSize: "12.5px", fontWeight: 600, color: COLORS.inkOnCream, lineHeight: 1.25, marginTop: "6px" }}>{p.name}</div>
                <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "11.5px", color: COLORS.amberDark, marginTop: "4px" }}>{p.salePrice} ₺/{p.unit}</div>
                <div style={{ fontSize: "10px", color: COLORS.muted, marginTop: "2px" }}>Stok: {p.stock - inCart}{inCart > 0 ? ` (${inCart} sepette)` : ""}</div>
              </div>
            );
          })}
        </div>
      </div>
      <div style={{ width: "340px", flexShrink: 0, display: "flex", flexDirection: "column", background: "#FBF9F3" }}>
        <div style={{ padding: "16px 20px 10px", borderBottom: `1px solid ${COLORS.line}` }}>
          <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "15.5px", color: COLORS.inkOnCream }}>Sepet</div>
          <div style={{ fontSize: "11.5px", color: COLORS.muted, marginTop: "2px" }}>{itemCount > 0 ? `${itemCount} ürün` : "Henüz ürün eklenmedi"}</div>
        </div>
        <div style={{ flex: 1, overflowY: "auto", padding: "10px 16px" }}>
          {cartLines.length === 0 && <div style={{ textAlign: "center", padding: "50px 10px", color: COLORS.muted, fontSize: "12.5px" }}>Ürüne tıklayarak sepete ekle.</div>}
          {cartLines.map((l) => (
            <div key={l.product.id} style={{ display: "flex", alignItems: "center", gap: "9px", padding: "8px 6px", borderBottom: `1px solid ${COLORS.line}` }}>
              <ProductThumb product={l.product} size={30} />
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: "12.5px", fontWeight: 600, color: COLORS.inkOnCream }}>{l.product.name}</div>
                <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "11px", color: COLORS.muted }}>{l.product.salePrice} ₺ × {l.qty}</div>
              </div>
              <Stepper compact value={l.qty} onChange={(v) => setCartQty(l.product.id, v)} />
            </div>
          ))}
        </div>
        <div style={{ padding: "14px 20px", borderTop: `1px solid ${COLORS.line}` }}>
          <div style={{ display: "flex", gap: "6px", marginBottom: "12px" }}>
            {PAYMENT_METHODS.map((m) => (
              <button key={m} onClick={() => setPayment(m)} style={{ flex: 1, padding: "8px 4px", borderRadius: "9px", fontSize: "11.5px", fontWeight: 600, border: `1.5px solid ${payment === m ? COLORS.amber : COLORS.line}`, background: payment === m ? "rgba(217,142,43,0.16)" : COLORS.paper, color: payment === m ? COLORS.amberDark : COLORS.muted, cursor: "pointer" }}>{m}</button>
            ))}
          </div>
          {payment === "Veresiye" && (
            <div style={{ marginBottom: "12px" }}>
              <FieldLabel>Cari seç</FieldLabel>
              <select value={selectedCariId} onChange={(e) => setSelectedCariId(e.target.value)} style={{ ...inputStyle, borderColor: selectedCariId ? COLORS.amber : COLORS.line }}>
                <option value="">Müşteri seç...</option>
                {customers.map((c) => <option key={c.id} value={c.id}>{c.name} (mevcut: {currentBalance(c)} ₺)</option>)}
              </select>
            </div>
          )}
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: "12px" }}>
            <span style={{ fontSize: "13px", color: COLORS.muted, fontWeight: 600 }}>Toplam</span>
            <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "22px", fontWeight: 700, color: COLORS.navy }}>{total.toLocaleString("tr-TR")} ₺</span>
          </div>
          <button className="primary-btn" disabled={cartLines.length === 0 || (payment === "Veresiye" && !selectedCariId)} onClick={completeSale} style={{ width: "100%", padding: "13px 0", border: "none", borderRadius: "10px", background: cartLines.length === 0 || (payment === "Veresiye" && !selectedCariId) ? COLORS.line : COLORS.amber, color: cartLines.length === 0 || (payment === "Veresiye" && !selectedCariId) ? COLORS.muted : COLORS.navy, fontWeight: 700, fontSize: "14px" }}>
            {completedFlash ? "✓ Satış tamamlandı" : payment === "Veresiye" ? "Veresiye yaz" : "Satışı tamamla"}
          </button>
        </div>
      </div>
      {quickAddOpen && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(16,27,61,0.45)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 55 }}>
          <div style={{ width: "380px", maxWidth: "92vw", background: COLORS.cream, borderRadius: "16px", padding: "22px", boxShadow: "0 20px 50px rgba(0,0,0,0.3)" }}>
            <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "17px", color: COLORS.inkOnCream, marginBottom: "4px" }}>Bu barkod kayıtlı değil</div>
            <div style={{ fontSize: "12px", color: COLORS.muted, marginBottom: "16px" }}>Hızlıca kaydedip aynı anda sepete ekleyelim.</div>
            <div style={{ marginBottom: "12px" }}>
              <FieldLabel>Barkod</FieldLabel>
              <input value={quickAddForm.barcode} readOnly style={{ ...inputStyle, color: COLORS.muted, background: COLORS.line }} />
            </div>
            <div style={{ marginBottom: "12px" }}>
              <FieldLabel>Ürün adı</FieldLabel>
              <input value={quickAddForm.name} onChange={(e) => setQuickAddForm((p) => ({ ...p, name: e.target.value }))} placeholder="ör. Ayran" autoFocus style={inputStyle} />
            </div>
            <div style={{ display: "flex", gap: "10px", marginBottom: "12px" }}>
              <div style={{ flex: 1 }}>
                <FieldLabel>Kategori</FieldLabel>
                <select value={quickAddForm.cat} onChange={(e) => setQuickAddForm((p) => ({ ...p, cat: e.target.value }))} style={inputStyle}>
                  {CATEGORIES.map((c) => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div style={{ flex: 1 }}>
                <FieldLabel>Birim</FieldLabel>
                <select value={quickAddForm.unit} onChange={(e) => setQuickAddForm((p) => ({ ...p, unit: e.target.value }))} style={inputStyle}>
                  {UNITS.map((u) => <option key={u} value={u}>{u}</option>)}
                </select>
              </div>
            </div>
            <div style={{ display: "flex", gap: "10px", marginBottom: "12px" }}>
              <div style={{ flex: 1 }}>
                <FieldLabel>Satış fiyatı</FieldLabel>
                <input type="number" value={quickAddForm.salePrice} onChange={(e) => setQuickAddForm((p) => ({ ...p, salePrice: e.target.value }))} placeholder="0" style={inputStyle} />
              </div>
              <div style={{ flex: 1 }}>
                <FieldLabel>Mevcut stok</FieldLabel>
                <input type="number" value={quickAddForm.stock} onChange={(e) => setQuickAddForm((p) => ({ ...p, stock: e.target.value }))} style={inputStyle} />
              </div>
            </div>
            <div style={{ display: "flex", gap: "10px" }}>
              <button className="ghost-btn" onClick={() => setQuickAddOpen(false)} style={{ flex: 1, border: `1.5px solid ${COLORS.line}`, background: "transparent", borderRadius: "10px", padding: "11px 0", fontWeight: 600, fontSize: "13.5px", color: COLORS.muted }}>Vazgeç</button>
              <button className="primary-btn" onClick={saveQuickAdd} style={{ flex: 1, border: "none", borderRadius: "10px", padding: "11px 0", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13.5px" }}>Kaydet ve sepete ekle</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ---------- Cari ----------
function CariView({ cariList, setCariList, addCariTransaction, currentBalance }) {
  const [selectedId, setSelectedId] = useState(cariList[0]?.id);
  const [filter, setFilter] = useState("hepsi");
  const [query, setQuery] = useState("");
  const [txFormOpen, setTxFormOpen] = useState(false);
  const [newCariOpen, setNewCariOpen] = useState(false);
  const [newCariForm, setNewCariForm] = useState({ name: "", phone: "", type: "musteri", creditLimit: "" });
  const [txForm, setTxForm] = useState({ type: "veresiyeSatis", amount: "", note: "" });

  const selected = cariList.find((c) => c.id === selectedId);
  const filtered = cariList.filter((c) => (filter === "hepsi" || c.type === filter) && c.name.toLocaleLowerCase("tr").includes(query.toLocaleLowerCase("tr")));
  const totalReceivable = cariList.reduce((sum, c) => sum + Math.max(0, currentBalance(c)), 0);
  const totalPayable = cariList.reduce((sum, c) => sum + Math.max(0, -currentBalance(c)), 0);
  const txTypeOptions = selected ? (selected.type === "musteri" ? [{ key: "veresiyeSatis", label: "Veresiye satış ekle" }, { key: "tahsilat", label: "Tahsilat al" }] : [{ key: "malAlimiVeresiye", label: "Mal alımı (veresiye)" }, { key: "odemeYap", label: "Ödeme yap" }]) : [];

  const openTxForm = () => { setTxForm({ type: txTypeOptions[0].key, amount: "", note: "" }); setTxFormOpen(true); };
  const saveTx = () => { const amt = Number(txForm.amount); if (!amt || amt <= 0 || !selected) return; addCariTransaction(selected.id, txForm.type, amt, txForm.note); setTxFormOpen(false); };
  const saveNewCari = () => {
    if (!newCariForm.name.trim()) return;
    const newCari = { id: "c" + Date.now(), name: newCariForm.name, phone: newCariForm.phone, type: newCariForm.type, creditLimit: Number(newCariForm.creditLimit) || 0, transactions: [] };
    setCariList((prev) => [newCari, ...prev]);
    setSelectedId(newCari.id); setNewCariOpen(false); setNewCariForm({ name: "", phone: "", type: "musteri", creditLimit: "" });
  };

  return (
    <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
      <div style={{ width: "340px", flexShrink: 0, display: "flex", flexDirection: "column", borderRight: `1px solid ${COLORS.line}` }}>
        <div style={{ padding: "18px 18px 10px", borderBottom: `1px solid ${COLORS.line}` }}>
          <div style={{ display: "flex", alignItems: "center", marginBottom: "12px" }}>
            <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "17px", color: COLORS.inkOnCream, marginRight: "auto" }}>Cari Hesaplar</div>
            <button className="primary-btn" onClick={() => setNewCariOpen(true)} style={{ border: "none", borderRadius: "8px", padding: "7px 12px", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "12px" }}>+ Yeni</button>
          </div>
          <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Cari ara..." style={{ ...inputStyle, marginBottom: "10px" }} />
          <div style={{ display: "flex", gap: "6px" }}>
            {[{ key: "hepsi", label: "Hepsi" }, { key: "musteri", label: "Müşteri" }, { key: "tedarikci", label: "Tedarikçi" }].map((f) => (
              <button key={f.key} className="cat-chip" onClick={() => setFilter(f.key)} style={{ padding: "5px 11px", borderRadius: "999px", fontSize: "11.5px", fontWeight: 600, border: `1.5px solid ${filter === f.key ? COLORS.amber : COLORS.line}`, background: filter === f.key ? "rgba(217,142,43,0.16)" : COLORS.paper, color: filter === f.key ? COLORS.amberDark : COLORS.muted }}>{f.label}</button>
            ))}
          </div>
        </div>
        <div style={{ display: "flex", gap: "10px", padding: "12px 18px", borderBottom: `1px solid ${COLORS.line}` }}>
          <div style={{ flex: 1 }}><div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "15px", fontWeight: 700, color: COLORS.green }}>{totalReceivable.toLocaleString("tr-TR")} ₺</div><div style={{ fontSize: "10px", color: COLORS.muted }}>toplam alacak</div></div>
          <div style={{ flex: 1 }}><div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "15px", fontWeight: 700, color: COLORS.red }}>{totalPayable.toLocaleString("tr-TR")} ₺</div><div style={{ fontSize: "10px", color: COLORS.muted }}>toplam borç</div></div>
        </div>
        <div style={{ flex: 1, overflowY: "auto", padding: "10px 14px" }}>
          {filtered.map((c) => {
            const bal = currentBalance(c);
            const active = c.id === selectedId;
            return (
              <div key={c.id} className="cari-row" onClick={() => setSelectedId(c.id)} style={{ background: active ? COLORS.paper : "transparent", border: `1.5px solid ${active ? COLORS.amber : "transparent"}`, borderRadius: "12px", padding: "10px 12px", marginBottom: "6px" }}>
                <div style={{ fontSize: "13px", fontWeight: 600, color: COLORS.inkOnCream }}>{c.name}</div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: "4px" }}>
                  <Pill tone="muted">{c.type === "musteri" ? "Müşteri" : "Tedarikçi"}</Pill>
                  <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "12.5px", fontWeight: 700, color: bal > 0 ? COLORS.green : bal < 0 ? COLORS.red : COLORS.muted }}>{bal === 0 ? "0 ₺" : bal > 0 ? `+${bal} ₺` : `${bal} ₺`}</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
      <div style={{ flex: 1, display: "flex", flexDirection: "column", minWidth: 0 }}>
        {selected && (
          <>
            <div style={{ padding: "18px 24px", borderBottom: `1px solid ${COLORS.line}`, display: "flex", alignItems: "flex-start" }}>
              <div style={{ marginRight: "auto" }}>
                <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "18px", color: COLORS.inkOnCream }}>{selected.name}</div>
                <div style={{ fontSize: "12px", color: COLORS.muted, marginTop: "3px" }}>{selected.phone} · {selected.type === "musteri" ? "Müşteri" : "Tedarikçi"}</div>
              </div>
              <div style={{ textAlign: "right", marginRight: "18px" }}>
                <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "22px", fontWeight: 700, color: currentBalance(selected) >= 0 ? COLORS.green : COLORS.red }}>{currentBalance(selected).toLocaleString("tr-TR")} ₺</div>
                <div style={{ fontSize: "10.5px", color: COLORS.muted }}>{currentBalance(selected) >= 0 ? "alacağımız" : "borcumuz"}</div>
              </div>
              <button className="primary-btn" onClick={openTxForm} style={{ border: "none", borderRadius: "10px", padding: "10px 16px", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13px" }}>+ İşlem ekle</button>
            </div>
            <div style={{ flex: 1, overflowY: "auto", padding: "16px 24px" }}>
              {selected.transactions.length === 0 ? <div style={{ textAlign: "center", padding: "50px 10px", color: COLORS.muted, fontSize: "12.5px" }}>Henüz işlem yok.</div> :
                [...selected.transactions].reverse().map((t) => (
                  <div key={t.id} style={{ display: "flex", alignItems: "center", gap: "12px", background: COLORS.paper, border: `1px solid ${COLORS.line}`, borderRadius: "12px", padding: "11px 14px", marginBottom: "8px" }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: "13px", fontWeight: 600, color: COLORS.inkOnCream }}>{TX_LABELS[t.type]}</div>
                      {t.note && <div style={{ fontSize: "11.5px", color: COLORS.muted, marginTop: "2px" }}>{t.note}</div>}
                      <div style={{ fontSize: "10.5px", color: COLORS.muted, marginTop: "2px" }}>{t.timestamp}</div>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "14px", fontWeight: 700, color: t.type === "veresiyeSatis" || t.type === "malAlimiVeresiye" ? COLORS.inkOnCream : COLORS.green }}>{t.type === "tahsilat" || t.type === "odemeYap" ? "−" : "+"}{t.amount} ₺</div>
                      <div style={{ fontSize: "10px", color: COLORS.muted }}>bakiye: {t.balanceAfter} ₺</div>
                    </div>
                  </div>
                ))}
            </div>
          </>
        )}
      </div>
      {txFormOpen && selected && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(16,27,61,0.45)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 50 }}>
          <div style={{ width: "380px", maxWidth: "92vw", background: COLORS.cream, borderRadius: "16px", padding: "22px", boxShadow: "0 20px 50px rgba(0,0,0,0.3)" }}>
            <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "17px", color: COLORS.inkOnCream, marginBottom: "16px" }}>{selected.name} — yeni işlem</div>
            <div style={{ marginBottom: "12px" }}><FieldLabel>İşlem türü</FieldLabel><select value={txForm.type} onChange={(e) => setTxForm((p) => ({ ...p, type: e.target.value }))} style={inputStyle}>{txTypeOptions.map((o) => <option key={o.key} value={o.key}>{o.label}</option>)}</select></div>
            <div style={{ marginBottom: "12px" }}><FieldLabel>Tutar</FieldLabel><input type="number" value={txForm.amount} onChange={(e) => setTxForm((p) => ({ ...p, amount: e.target.value }))} placeholder="0" style={inputStyle} /></div>
            <div style={{ marginBottom: "18px" }}><FieldLabel>Not (opsiyonel)</FieldLabel><input value={txForm.note} onChange={(e) => setTxForm((p) => ({ ...p, note: e.target.value }))} placeholder="ör. hangi ürünler" style={inputStyle} /></div>
            <div style={{ display: "flex", gap: "10px" }}>
              <button className="ghost-btn" onClick={() => setTxFormOpen(false)} style={{ flex: 1, border: `1.5px solid ${COLORS.line}`, background: "transparent", borderRadius: "10px", padding: "11px 0", fontWeight: 600, fontSize: "13.5px", color: COLORS.muted }}>Vazgeç</button>
              <button className="primary-btn" onClick={saveTx} style={{ flex: 1, border: "none", borderRadius: "10px", padding: "11px 0", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13.5px" }}>Kaydet</button>
            </div>
          </div>
        </div>
      )}
      {newCariOpen && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(16,27,61,0.45)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 50 }}>
          <div style={{ width: "380px", maxWidth: "92vw", background: COLORS.cream, borderRadius: "16px", padding: "22px", boxShadow: "0 20px 50px rgba(0,0,0,0.3)" }}>
            <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "17px", color: COLORS.inkOnCream, marginBottom: "16px" }}>Yeni cari ekle</div>
            <div style={{ marginBottom: "12px" }}><FieldLabel>Ad</FieldLabel><input value={newCariForm.name} onChange={(e) => setNewCariForm((p) => ({ ...p, name: e.target.value }))} placeholder="ör. Mehmet Bey" style={inputStyle} /></div>
            <div style={{ marginBottom: "12px" }}><FieldLabel>Telefon</FieldLabel><input value={newCariForm.phone} onChange={(e) => setNewCariForm((p) => ({ ...p, phone: e.target.value }))} placeholder="05xx xxx xx xx" style={inputStyle} /></div>
            <div style={{ display: "flex", gap: "10px", marginBottom: "18px" }}>
              <div style={{ flex: 1 }}><FieldLabel>Tür</FieldLabel><select value={newCariForm.type} onChange={(e) => setNewCariForm((p) => ({ ...p, type: e.target.value }))} style={inputStyle}><option value="musteri">Müşteri</option><option value="tedarikci">Tedarikçi</option></select></div>
              <div style={{ flex: 1 }}><FieldLabel>Veresiye limiti</FieldLabel><input type="number" value={newCariForm.creditLimit} onChange={(e) => setNewCariForm((p) => ({ ...p, creditLimit: e.target.value }))} placeholder="0" style={inputStyle} /></div>
            </div>
            <div style={{ display: "flex", gap: "10px" }}>
              <button className="ghost-btn" onClick={() => setNewCariOpen(false)} style={{ flex: 1, border: `1.5px solid ${COLORS.line}`, background: "transparent", borderRadius: "10px", padding: "11px 0", fontWeight: 600, fontSize: "13.5px", color: COLORS.muted }}>Vazgeç</button>
              <button className="primary-btn" onClick={saveNewCari} style={{ flex: 1, border: "none", borderRadius: "10px", padding: "11px 0", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "13.5px" }}>Kaydet</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ---------- Siparişler ----------
function orderTotal(order) { return order.items.reduce((sum, i) => sum + i.price * i.qty, 0); }

function SiparislerView({ orders, setOrders, adjustStock, logMovement }) {
  const [advanceFlash, setAdvanceFlash] = useState(null);

  const advanceStatus = (orderId) => {
    const order = orders.find((o) => o.id === orderId);
    if (!order) return;
    const idx = STATUS_FLOW.indexOf(order.status);
    const next = STATUS_FLOW[Math.min(idx + 1, STATUS_FLOW.length - 1)];
    if (next === "tamamlandi" && order.status !== "tamamlandi") {
      order.items.forEach((it) => {
        adjustStock(it.productId, -it.qty);
        logMovement({ productName: it.name, emoji: "🛵", type: "satis", quantity: -it.qty, unit: it.unit, source: "depup", relatedOrderId: order.id, note: `Depup siparişi — ${order.customerName}` });
      });
    }
    setOrders((prev) => prev.map((o) => (o.id === orderId ? { ...o, status: next } : o)));
    setAdvanceFlash(orderId);
    setTimeout(() => setAdvanceFlash(null), 900);
  };

  const columns = STATUS_FLOW.map((key) => ({ key, label: STATUS_LABEL[key], orders: orders.filter((o) => o.status === key) }));

  return (
    <>
      <div style={{ padding: "18px 24px", borderBottom: `1px solid ${COLORS.line}`, display: "flex", alignItems: "center", flexShrink: 0 }}>
        <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 600, fontSize: "19px", color: COLORS.inkOnCream, marginRight: "10px" }}>Siparişler</div>
        <span style={{ fontSize: "12px", color: COLORS.muted }}>Depup üzerinden gelen siparişler, otomatik burada görünür. Tamamlanınca stok otomatik düşer.</span>
      </div>
      <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
        {columns.map((col, i) => (
          <div key={col.key} style={{ flex: 1, display: "flex", flexDirection: "column", minWidth: 0, borderRight: i < columns.length - 1 ? `1px solid ${COLORS.line}` : "none" }}>
            <div style={{ padding: "12px 14px", display: "flex", alignItems: "center", gap: "8px", borderBottom: `1px solid ${COLORS.line}`, flexShrink: 0 }}>
              <Pill tone={STATUS_TONE[col.key]}>{col.label}</Pill>
              <span style={{ fontSize: "11px", color: COLORS.muted }}>{col.orders.length}</span>
            </div>
            <div style={{ flex: 1, overflowY: "auto", padding: "10px" }}>
              {col.orders.length === 0 && <div style={{ textAlign: "center", padding: "24px 6px", color: COLORS.muted, fontSize: "11.5px" }}>—</div>}
              {col.orders.map((o) => (
                <div key={o.id} className={advanceFlash === o.id ? "flash" : ""} style={{ background: COLORS.paper, border: `1px solid ${COLORS.line}`, borderRadius: "12px", padding: "12px", marginBottom: "10px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "6px" }}>
                    <div style={{ fontSize: "12.5px", fontWeight: 700, color: COLORS.inkOnCream, lineHeight: 1.3 }}>{o.customerName}</div>
                    <span style={{ fontSize: "10px", color: COLORS.muted, whiteSpace: "nowrap", marginLeft: "6px" }}>{o.createdAt}</span>
                  </div>
                  <div style={{ display: "flex", alignItems: "center", gap: "5px", marginBottom: "8px" }}>
                    <span style={{ fontSize: "13px" }}>{SERVICE_ICON[o.serviceMode]}</span>
                    <span style={{ fontSize: "10.5px", color: COLORS.muted, fontWeight: 600 }}>{SERVICE_LABEL[o.serviceMode]}</span>
                    {o.address && <span style={{ fontSize: "10px", color: COLORS.muted }}>· {o.address}</span>}
                  </div>
                  <div style={{ marginBottom: "8px" }}>
                    {o.items.map((it, idx) => (
                      <div key={idx} style={{ display: "flex", justifyContent: "space-between", fontSize: "11px", color: COLORS.inkOnCream, padding: "1.5px 0" }}>
                        <span>{it.qty} {it.unit} {it.name}</span>
                        <span style={{ fontFamily: "'JetBrains Mono', monospace", color: COLORS.muted }}>{it.price * it.qty} ₺</span>
                      </div>
                    ))}
                  </div>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", paddingTop: "6px", borderTop: `1px dashed ${COLORS.line}` }}>
                    <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "13px", fontWeight: 700, color: COLORS.navy }}>{orderTotal(o)} ₺</span>
                    {o.status !== "tamamlandi" && <button className="advance-btn" onClick={() => advanceStatus(o.id)} style={{ border: "none", borderRadius: "8px", padding: "6px 10px", background: COLORS.amber, color: COLORS.navy, fontWeight: 700, fontSize: "10.5px" }}>{NEXT_ACTION_LABEL[o.status]}</button>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </>
  );
}
